VALUES
  ('cpa-moex-00511', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '與決策有關之成本，下列敘述何者正確？', '["機會成本（opportunitycosts）係指選擇了某一方案而拒絕其他方案，所放棄的總利益", "變動成本（variablecosts）一定是攸關成本（relevantcosts），而固定成本（fixedcosts）一定 是無關成本", "付現成本（out-of-pocketcosts）係指須於現在或未來支付現金的成本，一定是攸關成本", "不論選擇何種方案均不受影響之成本，即為無差異成本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00512', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '近年來，企業經營環境愈來愈重視企業社會責任（corporatesocialresponsibility）及永續發展 （sustainability）議題。如果公司管理會計人員想要符合此一發展趨勢，下列那一種為錯誤作法？', '["檢討公司品質成本，使品質更符合消費者預期", "檢討業務員的銷售績效報告，淘汰短期銷售未達標準的員工", "檢討廠房設備效能，汰換為更具節能減碳設施", "檢討廣告企劃支出，以強化公司社會公益形象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00513', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '中華公司有甲、乙服務部門及丙、丁生產部門。服務部門成本採用逐步分攤法分攤給生產部 門，依甲、乙部門次序分攤服務成本，甲服務部門成本採服務小時分攤，乙服務部門成本採 服務人次分攤。相關資訊如下： 甲服務部門 乙服務部門 丙生產部門 丁生產部門 成本預算數 $1,550,000 $500,000 $512,500 $615,000 服務小時 ---- 2,600 5,400 7,950 服務人次 1,350 ---- 4,500 5,100 甲服務部門分攤給丙生產部門之服務部門成本，最接近下列何者？', '["$169,280", "$173,510", "$524,765", "$626,965"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00514', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司生產並採直銷方式出售家電用品，直接原料成本$24,000，廠房折舊$32,000，水電費 $45,000，直銷人員佣金$22,000，行銷主管薪資$38,000，組裝人員薪資$51,000，保全人員薪 水$18,000，廠長薪水$30,000，甲公司主要成本（PrimeCosts）為何？', '["$46,000", "$75,000", "$200,000", "$260,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00515', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司以機器小時分攤製造費用，預計製造費用$8,160,000，實際製造費用$7,106,000。預計 機器運轉時數為136,000小時；地震停電導致實際機器運轉時數僅110,500小時。甲公司當年度 製造費用依預計製造費用分攤率分攤，下列何者正確？', '["多分攤$476,000", "少分攤$476,000", "多分攤$1,054,000", "少分攤$1,054,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00516', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '對總預算（masterbudget）之敘述，下列何者錯誤？', '["銷售預算屬於營業預算（operatingbudget）的範圍", "財務預算（financialbudget）是總預算的一部分", "資本預算不是財務預算的範圍", "現金預算是財務預算的範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00517', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '臺中公司預計販售58,000單位商品，每單位售價26元，直接材料每單位6元，直接製造人工成 本每單位10元，製造費用每單位1.66元。 下列為存貨資料： 直接材料 期初存貨：48,000單位 期末存貨：48,000單位 在製品 期初存貨：0單位 期末存貨：0單位 完成品 期初存貨：2,400單位 期末存貨：5,600單位 該公司生產所投入的直接材料成本、直接人工成本及製造費用各為何？', '["$288,000；$480,000；$79,680", "$328,800；$548,000；$90,968", "$348,000；$548,000；$96,280", "$367,200；$612,000；$101,592"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00518', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司生產兩種主要產品K1和K2，兩產品相關資料如下： 產品 生產量 分離點後額外成本 銷售量 銷售價格 K1 12,500 $ 10,500 12,000 $45 K2 17,500 $480,000 15,000 $80 共同製程中的聯合成本總計$530,000，若甲公司採用固定毛利率淨變現價值法，則產品K2需 分攤多少聯合成本？', '["$341,100", "$248,000", "$223,800", "$192,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00519', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列是甲公司20X1年有關實際與預算的相關資料： 實際數目 靜態預算 銷售量 25,000 30,000 變動成本 $125,000 $180,000 固定成本 $48,000 $50,000 該公司每單位預算售價$50，實際售價$60，則營業利益的靜態預算差異與彈性預算差異各為何？', '["營業利益靜態預算差異：$220,000（不利）；營業利益彈性預算差異：$277,000（有利）", "營業利益靜態預算差異：$277,000（有利）；營業利益彈性預算差異：$57,000（有利）", "營業利益靜態預算差異：$57,000（有利）；營業利益彈性預算差異：$277,000（有利）", "營業利益靜態預算差異：$57,000（有利）；營業利益彈性預算差異：$220,000（不利）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00520', 'cpa', 'cpa-moex-110-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '穩康公司產品單位成本資料如下： 直接材料$50，直接人工$40，變動製造費用$70，固定製造費用$80，變動銷售及管理費用$35， 固定銷售及管理費用$65，在全部成本法（fullcosting）及變動成本法（variablecosting）下存 貨的單位成本分別為何？', '["全部成本法下存貨的單位成本$240；變動成本法下存貨的單位成本$160", "全部成本法下存貨的單位成本$320；變動成本法下存貨的單位成本$160", "全部成本法下存貨的單位成本$240；變動成本法下存貨的單位成本$195", "全部成本法下存貨的單位成本$320；變動成本法下存貨的單位成本$195"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "c826e989d219", "answer_pdf_sha1": "23a9597d12cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
